using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}

int n, ans, vis[22];
string s[22], st;

int check(string a, string b)
{
	int len = min(a.size(), b.size());
	for (int i = 1; i < len; i++)
	{
		if (a.substr(a.size() - i, i) == b.substr(0, i))return i;
	}
	return 0;
}

void dfs(string str, int len)
{
	if (len > ans)
	{
		ans = len;
	}
	for (int i = 1; i <= n; i++)
	{
		if (len == 1)
		{
			if (s[i][0] == str[0])
			{
				vis[i]++;
				dfs(s[i], s[i].size());
				vis[i]--;
			}
		}
		else
		{
			int k = check(str, s[i]);
			if (k && vis[i] < 2)
			{
				vis[i]++;
				dfs(s[i], len + s[i].size() - k);
				vis[i]--;
			}
		}
	}
}

int main()
{
	cin >> n;
	for (int i = 1; i <= n; i++)
	{
		cin >> s[i];
	}
	cin >> st;
	dfs(st, 1);
	cout << ans;
	return 0;
}
